import{_ as t,o,c as a,ak as r}from"./chunks/framework.tZEZYUNo.js";const h=JSON.parse('{"title":"Project standards and “valid” packages","description":"","frontmatter":{},"headers":[],"relativePath":"project-standards.md","filePath":"project-standards.md"}'),n={name:"project-standards.md"};function d(s,e,i,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="project-standards-and-valid-packages" tabindex="-1">Project standards and “valid” packages <a class="header-anchor" href="#project-standards-and-valid-packages" aria-label="Permalink to “Project standards and “valid” packages”">​</a></h1><p>A <strong>valid</strong> monorepo package in this repository is a workspace member that Nx can execute targets for and that meets the expectations below. Shipping WordPress plugins and themes live under <code>plugins/&lt;slug&gt;/</code> or <code>themes/&lt;slug&gt;/</code>.</p><h2 id="required-for-application-packages-plugins-and-themes" tabindex="-1">Required for application packages (plugins and themes) <a class="header-anchor" href="#required-for-application-packages-plugins-and-themes" aria-label="Permalink to “Required for application packages (plugins and themes)”">​</a></h2><ol><li><p><strong><code>project.json</code></strong> (Nx) at the package root</p><ul><li>Includes a unique <code>name</code> matching the Nx project name used in tags (see <a href="./versioning">Versioning</a>).</li><li>Declares <code>root</code>, <code>projectType: &quot;application&quot;</code>, and a <code>targets</code> object listing the targets this package supports (empty objects inherit defaults from <code>nx.json</code>).</li></ul></li><li><p><strong><code>package.json</code></strong></p><ul><li>Required for <code>@wordpress/scripts</code> and workspace tooling.</li><li>Must declare <strong>its own</strong> runtime and dev dependencies; do not rely on accidental hoisting (see <a href="./package-management">Package management</a>).</li></ul></li><li><p><strong><code>composer.json</code></strong> (when PHP / Composer is used)</p><ul><li>Defines the Composer package name, autoloading, and scripts such as <code>test</code> for integration tests.</li><li>Path repositories to monorepo packages (for example <code>packages/phpunit-config</code>) must be explicit where needed.</li></ul></li><li><p><strong>Targets and scripts</strong> Implement the targets your project needs, aligned with <a href="https://github.com/bcgov/bcew-monorepo/blob/main/nx.json" target="_blank" rel="noreferrer"><code>nx.json</code> defaults</a>:</p><table tabindex="0"><thead><tr><th>Target</th><th>Typical use</th></tr></thead><tbody><tr><td><code>composer-install</code></td><td><code>composer install</code> in the project root</td></tr><tr><td><code>build</code></td><td><code>wp-scripts build</code> → <code>dist/</code></td></tr><tr><td><code>start</code></td><td><code>wp-scripts start</code> (watch)</td></tr><tr><td><code>wp-env-start</code> / <code>wp-env-stop</code> / <code>wp-env-clean</code></td><td>Local WordPress via <code>@wordpress/env</code></td></tr><tr><td><code>test-e2e</code></td><td>Playwright via <code>wp-scripts test-playwright</code></td></tr><tr><td><code>test-integration</code></td><td>PHPUnit inside <code>wp-env</code></td></tr><tr><td><code>test-screenshot</code></td><td>Playwright visual regression tests, comparing with committed screenshots, generally only used by CI/CD.</td></tr><tr><td><code>test-screenshot-generate</code></td><td>Generate new Playwright visual regression screenshots, necessary when CI/CD finds mismatch between screenshots.</td></tr></tbody></table><p>Root shortcuts such as <code>pnpm build</code> run <code>nx run-many</code> across all projects that define the target.</p></li><li><p><strong>Local environment</strong></p><ul><li><code>.wp-env.json</code> at the project root when using <code>wp-env</code>, consistent with generator output.</li></ul></li><li><p><strong>Documentation</strong></p><ul><li>For sidebar inclusion in the published docs site, add <code>docs/index.md</code> under the package. Optional pages are additional Markdown files in the same <code>docs/</code> folder. See <a href="./contributing">Contributing docs</a>.</li></ul></li></ol><h2 id="shared-libraries-packages" tabindex="-1">Shared libraries (<code>packages/</code>) <a class="header-anchor" href="#shared-libraries-packages" aria-label="Permalink to “Shared libraries (packages/)”">​</a></h2><p>Libraries (for example <code>packages/phpunit-config</code>) use a minimal <code>project.json</code> and supply Composer or npm metadata as needed. They are referenced by path from application <code>composer.json</code> files when appropriate.</p><h2 id="generators" tabindex="-1">Generators <a class="header-anchor" href="#generators" aria-label="Permalink to “Generators”">​</a></h2><p>Scaffold new work with the internal Nx plugin:</p><ul><li><strong>Theme:</strong> <code>npx nx generate monorepo:theme</code> then <code>pnpm install</code></li><li><strong>Plugin:</strong> <code>npx nx generate monorepo:plugin</code> then <code>pnpm install</code></li><li><strong>Block in existing plugin:</strong> <code>npx nx generate monorepo:block &lt;plugin&gt; &lt;block-name&gt;</code></li></ul><p>See the <a href="https://github.com/bcgov/bcew-monorepo/blob/main/tools/monorepo/README.md" target="_blank" rel="noreferrer">monorepo README</a> for details.</p><h2 id="labeler-configuration" tabindex="-1">Labeler configuration <a class="header-anchor" href="#labeler-configuration" aria-label="Permalink to “Labeler configuration”">​</a></h2><p>When adding a new top-level plugin or theme folder, update <a href="https://github.com/bcgov/bcew-monorepo/blob/main/.github/labeler.yml" target="_blank" rel="noreferrer"><code>.github/labeler.yml</code></a> so pull requests receive accurate area labels.</p>',12)])])}const u=t(n,[["render",d]]);export{h as __pageData,u as default};
